func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request body
	var req URLPreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: "Invalid JSON request"}
		sendJSONResponse(ctx, resp)
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := URLPreviewResponse{Error: "URL is required"}
		sendJSONResponse(ctx, resp)
		return
	}

	// Create fasthttp client with timeout and dual stack support
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialDualStack(addr)
		},
		ReadTimeout: 3 * time.Second,
	}

	// Create request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer func() {
		fasthttp.ReleaseRequest(httpReq)
		fasthttp.ReleaseResponse(httpResp)
	}()

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Execute request with redirects
	err := client.DoRedirects(httpReq, httpResp, 10) // Allow up to 10 redirects
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp := URLPreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		sendJSONResponse(ctx, resp)
		return
	}

	// Check if response is HTML
	contentType := string(httpResp.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusUnsupportedMediaType)
		resp := URLPreviewResponse{Error: "URL does not return HTML content"}
		sendJSONResponse(ctx, resp)
		return
	}

	// Parse HTML to extract title and description
	body := httpResp.Body()
	title, description := parseHTML(body)

	// Return successful response
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
	}
	sendJSONResponse(ctx, resp)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent []byte) (string, string) {
	var title, description string

	// Parse HTML
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Traverse the HTML tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract description from meta tag
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
