// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var findMeta func(*html.Node)
	findMeta = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = "description"
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findMeta(c)
		}
	}

	findMeta(doc)

	// Trim whitespace
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

// isPrivateIP checks if an IP address is private
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip4[0] == 127 {
			return true
		}
		return false
	}

	// Check IPv6 private ranges
	// ::1/128 (loopback)
	if ip.IsLoopback() {
		return true
	}
	// fc00::/7 (unique local)
	if ip[0] == 0xfc || ip[0] == 0xfd {
		return true
	}
	// fe80::/10 (link-local)
	if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}

	return false
}

// isLocalhost checks if the hostname is localhost
func isLocalhost(hostname string) bool {
	localhostPatterns := []string{
		"localhost",
		"localhost.",
		"localhost.localdomain",
		"local",
	}

	hostname = strings.ToLower(hostname)
	for _, pattern := range localhostPatterns {
		if hostname == pattern || strings.HasPrefix(hostname, pattern+".") {
			return true
		}
	}
	return false
}

