)

// Request structure for incoming JSON
type URLRequest struct {
	URL string `json:"url"`
}

// Response structure for outgoing JSON
type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests with JSON body containing a URL,
// fetches the HTML content, extracts title and meta description
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("Invalid JSON")
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("URL is required")
		return
	}

	// Create HTTP client with timeout and IP restrictions
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Extract host from address for IP validation
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If no port, use the address as host
				host = addr
			}

			// Parse IP to check if it's private
			ip := net.ParseIP(host)
			if ip != nil && isPrivateIP(ip) {
				return nil, net.ErrClosed
			}

			// Dial with timeout if IP is public
			return fasthttp.DialTimeout(addr, 10*time.Second)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnWaitTimeout:  30 * time.Second,
	}

	// Prepare request
	httpReq := fasthttp.AcquireRequest()
	httpRes := fasthttp.AcquireResponse()
	defer func() {
		fasthttp.ReleaseRequest(httpReq)
		fasthttp.ReleaseResponse(httpRes)
	}()

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request with timeout
	err := client.DoTimeout(httpReq, httpRes, 15*time.Second)
	if err != nil {
		sendError(ctx, "Failed to fetch URL: "+err.Error())
		return
	}

	// Check response status
	if statusCode := httpRes.StatusCode(); statusCode != fasthttp.StatusOK {
		sendError(ctx, "HTTP request failed with status code: "+string(httpRes.Header.StatusMessage()))
		return
	}

	// Parse HTML to extract title and description
	title, description := extractMetaData(httpRes.Body())

	// Prepare and send response
	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		sendError(ctx, "Failed to encode response: "+err.Error())
		return
	}
