// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection - prevent access to internal/private networks
	if isPrivateIP(parsedURL.Hostname()) {
		ctx.Error("Access to private networks is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// SSRF protection at connection level
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If no port, use the address directly
				host = addr
			}

			// Check if host is a private IP
			if isPrivateIP(host) {
				return nil, fmt.Errorf("access to private network blocked")
			}

			return fasthttp.DialDualStack(addr)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	freq.Header.Set("Accept-Language", "en-US,en;q=0.5")

	// Set timeout context
	client.ReadTimeout = 5 * time.Second
	client.WriteTimeout = 5 * time.Second

	maxRedirectCounts := 3 // Reduced from 10 to prevent infinite redirect loops
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit response size to prevent DoS
	maxBodySize := 1024 * 1024 // 1MB
	if len(bodyBytes) > maxBodySize {
		bodyBytes = bodyBytes[:maxBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var extractData func(*html.Node)
	extractData = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractData(c)
		}
	}

	extractData(doc)
	return title, description, nil
}

// isPrivateIP checks if an IP address belongs to a private network
func isPrivateIP(host string) bool {
	// First try to parse as IP
	if ip := net.ParseIP(host); ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified()
	}

	// If it's a hostname, check for localhost or internal domains
	host = strings.ToLower(host)
	return host == "localhost" || 
	       strings.HasSuffix(host, ".local") ||
	       strings.HasSuffix(host, ".internal") ||
	       strings.HasSuffix(host, ".localdomain")
}

