type URLRequest struct {
	URL string `json:"url"`
}

// Response structure for outgoing JSON
type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests with JSON body containing a URL
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("Invalid JSON")
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("URL is required")
		return
	}

	// Create fasthttp client with timeout and security restrictions
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialTimeout(addr, 5*time.Second)
		},
		MaxConnsPerHost: 1,
		ReadTimeout:     5 * time.Second,
		WriteTimeout:    5 * time.Second,
	}

	// Prepare request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer func() {
		fasthttp.ReleaseRequest(httpReq)
		fasthttp.ReleaseResponse(httpResp)
	}()

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request with timeout and redirect handling
	if err := client.DoTimeout(httpReq, httpResp, 10*time.Second); err != nil {
		sendError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	// Check response status
	if statusCode := httpResp.StatusCode(); statusCode != fasthttp.StatusOK {
		sendError(ctx, fmt.Sprintf("HTTP error: %d", statusCode))
		return
	}

	// Check content type
	contentType := string(httpResp.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		sendError(ctx, "URL does not return HTML content")
		return
	}

	// Limit response size to prevent DoS
	body := httpResp.Body()
	if len(body) > 1024*1024 { // 1MB limit
		body = body[:1024*1024]
	}

	// Parse HTML
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		sendError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	// Extract title
	title := doc.Find("title").First().Text()
	if title == "" {
		title = doc.Find("meta[property='og:title']").First().AttrOr("content", "")
	}

	// Extract description
	description := doc.Find("meta[name='description']").First().AttrOr("content", "")
	if description == "" {
		description = doc.Find("meta[property='og:description']").First().AttrOr("content", "")
	}

	// Clean up whitespace
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	// Prepare response
	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	// Send JSON response
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString("Failed to encode response")
	}
}

// Helper function to send error responses
func sendError(ctx *fasthttp.RequestCtx, message string) {
	preview := URLPreview{
		Error: message,
	}
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusBadRequest)
	json.NewEncoder(ctx).Encode(preview)
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not found")
		}
	})
}

