		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var findMeta func(*html.Node)
	findMeta = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						if attr.Val == "description" || 
						   attr.Val == "og:description" || 
						   attr.Val == "twitter:description" {
							name = attr.Val
						}
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description" || name == "twitter:description") && 
				   content != "" && description == "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findMeta(c)
		}
	}

	findMeta(doc)

	// Clean up the extracted text
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

// isPrivateIP checks if the hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Check for common internal/private hostname patterns
	privatePatterns := []string{
		"localhost",
		"127.",
		"192.168.",
		"10.",
		"172.16.",
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
		"169.254.",
		"::1",
		"fc00::",
		"fd00::",
		"fe80::",
	}

	for _, pattern := range privatePatterns {
		if strings.HasPrefix(hostname, pattern) {
			return true
		}
	}

	return false
}

