// validateHost prevents SSRF attacks by validating the host
func validateHost(host string) error {
	// Remove port if present
	if idx := strings.Index(host, ":"); idx != -1 {
		host = host[:idx]
	}

	// Security: Block private/internal IP addresses
	ip := net.ParseIP(host)
	if ip != nil {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
			return fmt.Errorf("access to private/internal IP addresses is not allowed")
		}
	}

	// Security: Block common internal domains
	internalDomains := []string{
		"localhost",
		"127.0.0.1",
		"::1",
		"0.0.0.0",
		"internal",
		"intranet",
		"local",
	}

	hostLower := strings.ToLower(host)
	for _, domain := range internalDomains {
		if strings.Contains(hostLower, domain) {
			return fmt.Errorf("access to internal domains is not allowed")
		}
	}

	return nil
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var extract func(*html.Node)
	extract = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var metaName, metaContent string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						metaName = attr.Val
					}
					if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				if strings.ToLower(metaName) == "description" && metaContent != "" {
					description = metaContent
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extract(c)
		}
	}

	extract(doc)

	// Trim whitespace and limit length for security
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	// Security: Limit output size to prevent DoS
	maxTitleLength := 200
	maxDescLength := 500

	if len(title) > maxTitleLength {
		title = title[:maxTitleLength] + "..."
	}
	if len(description) > maxDescLength {
		description = description[:maxDescLength] + "..."
	}

	return title, description, nil
}

