	"github.com/valyala/fasthttp"
)

// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var requestData struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &requestData); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if requestData.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Create fasthttp client with timeout and restricted network access
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Restrict to public IP ranges only (no private/internal networks)
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, try parsing as host without port
				host = addr
			}

			// Resolve host to check IP
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, fmt.Errorf("failed to resolve host: %v", err)
			}

			// Check each resolved IP
			for _, ip := range ips {
				// Block private/internal IP ranges
				if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
					return nil, fmt.Errorf("access to local/private network blocked")
				}

				// Block private IPv4 ranges
				if ip4 := ip.To4(); ip4 != nil {
					if (ip4[0] == 10) || // 10.0.0.0/8
						(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
						(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
						(ip4[0] == 169 && ip4[1] == 254) { // 169.254.0.0/16
						return nil, fmt.Errorf("access to private IP range blocked")
					}
				}
			}

			// Use default dialer with timeout
			dialer := &net.Dialer{
				Timeout:   10 * time.Second,
				KeepAlive: 30 * time.Second,
			}
			return dialer.Dial("tcp", addr)
		},
		ReadTimeout:          10 * time.Second,
		WriteTimeout:         10 * time.Second,
		MaxIdleConnDuration:  30 * time.Second,
		MaxConnWaitTimeout:   30 * time.Second,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer func() {
		fasthttp.ReleaseRequest(req)
		fasthttp.ReleaseResponse(resp)
	}()

	req.SetRequestURI(requestData.URL)
	req.Header.SetMethod("GET")
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	req.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	req.Header.Set("Accept-Language", "en-US,en;q=0.5")

	// Execute request with redirects and timeout
	err := client.DoTimeout(req, resp, 15*time.Second)
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Check response status
	if statusCode := resp.StatusCode(); statusCode != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("HTTP error: %d", statusCode), fasthttp.StatusBadGateway)
		return
	}

	// Check content type
	contentType := string(resp.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadRequest)
		return
	}

	// Parse HTML content
	bodyBytes := resp.Body()
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(bodyBytes)))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Extract title
	title := doc.Find("title").Text()

	// Extract meta description
	description := ""
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if content, exists := s.Attr("content"); exists {
			description = content
		}
	})

	// If no meta description found, try og:description
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if content, exists := s.Attr("content"); exists {
