	responseData := struct {
		URL         string `json:"url"`
		Title       string `json:"title"`
		Description string `json:"description"`
	}{
		URL:         requestData.URL,
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	// Set response headers and encode JSON
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)

	if err := json.NewEncoder(ctx).Encode(responseData); err != nil {
		ctx.Error(fmt.Sprintf("Failed to encode response: %v", err), fasthttp.StatusInternalServerError)
	}
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-url-preview":
			FetchURLPreview(ctx)
		default:
