package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Security configuration
const (
	maxResponseSize    = 10 * 1024 * 1024 // 10MB max response size
	maxRedirects       = 5                // Maximum redirects
	requestTimeout     = 15 * time.Second // Overall request timeout
	clientReadTimeout  = 10 * time.Second // Client read timeout
	clientWriteTimeout = 10 * time.Second // Client write timeout
)

// Blocked private IP ranges
var privateIPBlocks []*net.IPNet

func init() {
	// Initialize private IP blocks for SSRF protection
	for _, cidr := range []string{
		"10.0.0.0/8",     // Private
		"172.16.0.0/12",  // Private
		"192.168.0.0/16", // Private
		"127.0.0.0/8",    // Loopback
		"169.254.0.0/16", // Link-local
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 private
		"fe80::/10",      // IPv6 link-local
	} {
		_, block, _ := net.ParseCIDR(cidr)
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// validateURL performs security validation on the URL
func validateURL(rawURL string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(rawURL)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format")
	}

	// Validate scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("URL must use http or https scheme")
	}

	// Resolve host to IP for SSRF protection
	host := parsedURL.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("could not resolve host")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private/internal IPs is not allowed")
		}
	}

	// Validate port if present
	if parsedURL.Port() != "" {
		port := parsedURL.Port()
		if port == "22" || port == "21" || port == "25" || port == "110" || port == "143" {
			return nil, fmt.Errorf("access to service ports is not allowed")
		}
	}

	// Additional validation: prevent malformed URLs
	if strings.Contains(parsedURL.Host, "@") {
		return nil, fmt.Errorf("invalid URL format")
	}

	return parsedURL, nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set overall timeout for the entire handler
	timeoutTimer := time.AfterFunc(requestTimeout, func() {
		ctx.Error("Request timeout", fasthttp.StatusRequestTimeout)
		ctx.SetConnectionClose()
	})
	defer timeoutTimer.Stop()

	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Security validation
	_, err := validateURL(targetURL)
	if err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with security configurations
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         clientReadTimeout,
		WriteTimeout:        clientWriteTimeout,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     2, // Limit connections per host
		MaxConnWaitTimeout:  5 * time.Second,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Set headers to limit response size
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	freq.Header.Set("Accept-Language", "en-US,en;q=0.5")
	freq.Header.Set("Accept-Encoding", "gzip, deflate")

	// Configure response with size limit
	res.SkipBody = false
	res.SetConnectionClose()

	// Perform request with redirect limits
	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Check status code
	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Check content type
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	// Check response size
	bodyBytes := res.Body()
	if len(bodyBytes) > maxResponseSize {
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Prepare response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// For demonstration purposes - in production, use a proper HTML parser
	// like golang.org/x/net/html or github.com/PuerkitoBio/goquery

	// Simple implementation that reads the HTML and extracts basic metadata
	data, err := io.ReadAll(io.LimitReader(r, maxResponseSize))
	if err != nil {
		return "", "", err
	}

	html := string(data)

	// Extract title
	titleStart := strings.Index(html, "<title>")
	if titleStart != -1 {
		titleEnd := strings.Index(html[titleStart:], "</title>")
		if titleEnd != -1 {
			title = html[titleStart+7 : titleStart+titleEnd]
			title = strings.TrimSpace(title)
		}
	}

	// Extract meta description
	descStart := strings.Index(html, "name=\"description\"")
	if descStart == -1 {
		descStart = strings.Index(html, "name='description'")
	}

	if descStart != -1 {
		contentStart := strings.Index(html[descStart:], "content=")
		if contentStart != -1 {
			contentStart += descStart + 8
			quoteChar := html[contentStart-1]
			if quoteChar == '"' || quoteChar == '\'' {
				contentEnd := strings.Index(html[contentStart:], string(quoteChar))
				if contentEnd != -1 {
					description = html[contentStart : contentStart+contentEnd]
					description = strings.TrimSpace(description)
				}
			}
		}
	}

	return title, description, nil
}

