package main

import (
	"encoding/json"
	"fmt"
	"net"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// URLRequest represents the JSON request structure
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response structure
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request body
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "Invalid JSON request")
		return
	}

	// Validate URL
	if req.URL == "" {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "URL is required")
		return
	}

	// Create HTTP client with timeout and IP restrictions
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Restrict to public IP ranges only (no private/localhost)
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, try without port
				host = addr
			}

			ip := net.ParseIP(host)
			if ip == nil {
				// Try DNS resolution
				ips, err := net.LookupIP(host)
				if err != nil || len(ips) == 0 {
					return nil, fmt.Errorf("cannot resolve host: %s", host)
				}
				ip = ips[0]
			}

			// Check for private/localhost IPs
			if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
				return nil, fmt.Errorf("access to private/localhost IPs is not allowed")
			}

			// Check for IPv6 compatibility
			dialer := &net.Dialer{
				Timeout:   5 * time.Second,
				DualStack: true,
			}
			return dialer.Dial("tcp", addr)
		},
		ReadTimeout:        10 * time.Second,
		WriteTimeout:       10 * time.Second,
		MaxConnWaitTimeout: 10 * time.Second,
	}

	// Create request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL with redirect handling and timeout
	if err := client.DoRedirects(httpReq, httpResp, 5); err != nil {
		// Check if error is due to private IP restriction
		if strings.Contains(err.Error(), "private/localhost") {
			sendErrorResponse(ctx, fasthttp.StatusForbidden, 
				"Access to private/localhost URLs is not allowed")
			return
		}
		sendErrorResponse(ctx, fasthttp.StatusInternalServerError, 
			fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	// Check if response is HTML
	contentType := string(httpResp.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, 
			"URL does not return HTML content")
		return
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTML(httpResp.Body())
	if err != nil {
		sendErrorResponse(ctx, fasthttp.StatusInternalServerError, 
			fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	// Send successful response
	response := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(response); err != nil {
		sendErrorResponse(ctx, fasthttp.StatusInternalServerError, 
			fmt.Sprintf("Failed to encode response: %v", err))
	}
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(htmlContent []byte) (string, string, error) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", "", err
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract description from meta tag
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						if attr.Val == "description" || 
						   attr.Val == "og:description" || 
						   attr.Val == "twitter:description" {
							name = attr.Val
						}
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && content != "" && description == "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

// sendErrorResponse sends an error response in JSON format
func sendErrorResponse(ctx *fasthttp.RequestCtx, statusCode int, message string) {
	response := URLPreviewResponse{
		Error: message,
	}
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-url-preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not found")
		}
	})
}

