func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Only POST method is allowed")
		return
	}

	// Parse JSON request
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(fmt.Sprintf("Invalid JSON: %v", err))
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("URL is required")
		return
	}

	// Create HTTP client with dual stack support and timeout
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request
	reqFast := fasthttp.AcquireRequest()
	respFast := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqFast)
	defer fasthttp.ReleaseResponse(respFast)

	reqFast.SetRequestURI(req.URL)
	reqFast.Header.SetMethod(fasthttp.MethodGet)
	reqFast.Header.SetUserAgent("URLPreviewBot/1.0")

	// Fetch URL with redirects
	err := client.DoRedirects(reqFast, respFast, 10)
	if err != nil {
		sendErrorResponse(ctx, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	// Check response status
	if statusCode := respFast.StatusCode(); statusCode != fasthttp.StatusOK {
		sendErrorResponse(ctx, fmt.Sprintf("HTTP error: %d", statusCode))
		return
	}

	// Parse HTML content
	body := respFast.Body()
	title, description := extractMetaData(body)

	// Send response
	resp := Response{
		Title:       title,
		Description: description,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(resp)
}

func extractMetaData(htmlContent []byte) (string, string) {
	title := ""
	description := ""

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return title, description
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func sendErrorResponse(ctx *fasthttp.RequestCtx, errorMsg string) {
	resp := Response{
		Error: errorMsg,
	}
	ctx.SetStatusCode(fasthttp.StatusInternalServerError)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(resp)
}

