		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		MaxConnsPerHost: 2,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)
	req.Header.SetMethod("GET")
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	req.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Execute request with timeout and redirect limit
	err := client.DoTimeout(req, resp, 15*time.Second)
	if err != nil {
		return preview, fmt.Errorf("failed to fetch URL: %v", err)
	}

	// Check response status - accept 2xx status codes
	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		return preview, fmt.Errorf("HTTP error: %d", statusCode)
	}

	// Check content type
	contentType := string(resp.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return preview, fmt.Errorf("unsupported content type: %s", contentType)
	}

	// Parse HTML
	body := resp.Body()
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		return preview, fmt.Errorf("failed to parse HTML: %v", err)
	}

	// Extract title
	preview.Title = extractTitle(doc)

	// Extract meta description
	preview.Description = extractMetaDescription(doc)

	return preview, nil
}

func extractTitle(doc *goquery.Document) string {
	// Try to get title from <title> tag
	title := doc.Find("title").First().Text()
	if title != "" {
		return normalizeText(title)
	}

	// Fallback to OpenGraph title
	ogTitle := doc.Find("meta[property='og:title']").First()
	if titleAttr, exists := ogTitle.Attr("content"); exists && titleAttr != "" {
		return normalizeText(titleAttr)
	}

	// Fallback to Twitter card title
	twitterTitle := doc.Find("meta[name='twitter:title']").First()
	if titleAttr, exists := twitterTitle.Attr("content"); exists && titleAttr != "" {
		return normalizeText(titleAttr)
	}

	return ""
}

func extractMetaDescription(doc *goquery.Document) string {
	// Try to get description from meta description tag
	metaDesc := doc.Find("meta[name='description']").First()
	if desc, exists := metaDesc.Attr("content"); exists && desc != "" {
		return normalizeText(desc)
	}

	// Fallback to OpenGraph description
	ogDesc := doc.Find("meta[property='og:description']").First()
	if desc, exists := ogDesc.Attr("content"); exists && desc != "" {
		return normalizeText(desc)
	}

	// Fallback to Twitter card description
	twitterDesc := doc.Find("meta[name='twitter:description']").First()
	if desc, exists := twitterDesc.Attr("content"); exists && desc != "" {
		return normalizeText(desc)
	}

	// If no meta description found, extract first meaningful paragraph
	paragraphs := doc.Find("p").First().Text()
	if paragraphs != "" {
		return truncateText(normalizeText(paragraphs), 200)
	}

	return ""
}

func normalizeText(text string) string {
	// Remove extra whitespace and newlines
	text = strings.TrimSpace(text)

	// Replace multiple spaces with single space
	text = strings.Join(strings.Fields(text), " ")

	// Remove control characters
	var result strings.Builder
	for _, r := range text {
		if unicode.IsGraphic(r) && !unicode.IsControl(r) {
			result.WriteRune(r)
		}
	}

	return result.String()
}

func truncateText(text string, maxLength int) string {
	if len(text) <= maxLength {
		return text
	}

	// Truncate and add ellipsis
	truncated := text[:maxLength]
	// Find the last space to avoid cutting words
	if lastSpace := strings.LastIndex(truncated, " "); lastSpace > maxLength/2 {
		truncated = truncated[:lastSpace]
	}

	return truncated + "..."
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	})
}

