	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Set timeout headers and prevent caching
	freq.Header.Set("Cache-Control", "no-cache")
	freq.Header.Set("Pragma", "no-cache")

