// FetchURLPreview handles POST requests to fetch URL preview information
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONError(ctx, "Invalid JSON format")
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONError(ctx, "URL is required")
		return
	}

	// Create HTTP client with timeout and IP restrictions
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			// Restrict to public IP ranges only (no private/internal IPs)
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, try parsing as host without port
				host = addr
			}

			// Resolve to check IP
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, fmt.Errorf("failed to resolve host: %v", err)
			}

			// Check each resolved IP
			for _, ip := range ips {
				// Deny private/internal IPs
				if ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified() {
					return nil, fmt.Errorf("access to private/internal IPs is not allowed")
				}

				// Deny link-local and multicast addresses
				if ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() || ip.IsMulticast() {
					return nil, fmt.Errorf("access to restricted IP ranges is not allowed")
				}
			}

			// Use default dialer with timeout
			dialer := &net.Dialer{
				Timeout:   10 * time.Second,
				KeepAlive: 30 * time.Second,
			}
			return dialer.Dial("tcp", addr)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: time.Minute,
		MaxRedirectsCount:   5,
	}

	// Prepare request
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request with redirect handling
	err := client.Do(httpReq, httpResp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	// Check response status
	if statusCode := httpResp.StatusCode(); statusCode != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		sendJSONError(ctx, fmt.Sprintf("HTTP error: %d", statusCode))
		return
	}

	// Parse HTML to extract title and description
	title, description := extractMetaFromHTML(httpResp.Body())

	// Prepare and send response
	resp := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(resp)
}

// extractMetaFromHTML parses HTML content and extracts title and meta description
func extractMetaFromHTML(body []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var metaName, metaContent string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						metaName = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				if (metaName == "description" || metaName == "og:description") && metaContent != "" {
					description = metaContent
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

// sendJSONError sends an error response in JSON format
func sendJSONError(ctx *fasthttp.RequestCtx, message string) {
	resp := URLPreviewResponse{
		Error: message,
	}
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(resp)
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not found")
		}
	})
}

