// isPrivateIP checks if an IP address belongs to private network ranges
func isPrivateIP(host string) bool {
	ip := net.ParseIP(host)
	if ip == nil {
		// If it's not an IP, check if it's a localhost domain
		return strings.HasSuffix(host, ".local") || 
		       strings.HasSuffix(host, ".localhost") ||
		       host == "localhost"
	}

	// Check for private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127 ||
			ip4[0] == 0
	}

	// Check for private IPv6 ranges
	if ip6 := ip.To16(); ip6 != nil {
		return ip6[0] == 0xfd ||
			(ip6[0] == 0xfc) ||
			(ip6[0] == 0xfe && ip6[1] == 0x80) || // link-local
			(ip6[0] == 0xfe && ip6[1] == 0xc0) || // site-local
			(ip6[0] == 0x00) // unspecified
	}

	return false
}

// isValidHostname validates hostname format
func isValidHostname(host string) bool {
	if len(host) > 253 {
		return false
	}

	// Check each label
	labels := strings.Split(host, ".")
	for _, label := range labels {
		if len(label) < 1 || len(label) > 63 {
			return false
		}
		if label[0] == '-' || label[len(label)-1] == '-' {
			return false
		}
		for _, r := range label {
			if !((r >= 'a' && r <= 'z') || 
			     (r >= 'A' && r <= 'Z') || 
			     (r >= '0' && r <= '9') || 
			     r == '-') {
				return false
			}
		}
	}

	return true
}

