func isAllowedURL(url string) bool {
	// Basic SSRF protection - disallow internal/private addresses
	// In production, this should be more comprehensive
	if strings.Contains(url, "localhost") ||
		strings.Contains(url, "127.0.0.1") ||
		strings.Contains(url, "0.0.0.0") ||
		strings.Contains(url, "::1") ||
		strings.Contains(url, "169.254.") ||
		strings.Contains(url, "10.") ||
		strings.Contains(url, "172.16.") ||
		strings.Contains(url, "192.168.") {
		return false
	}
	return true
}

func extractTitleAndDescription(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var metaName, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						metaName = "description"
					}
					if attr.Key == "property" && attr.Val == "og:description" {
						metaName = "og:description"
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (metaName == "description" || metaName == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("Invalid JSON")
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString("URL is required")
		return
	}

	// SSRF protection
	if !isAllowedURL(req.URL) {
		preview := URLPreview{
			Error: "URL not allowed",
		}
		ctx.SetStatusCode(fasthttp.StatusForbidden)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(preview)
		return
	}

	client := getClient()
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	err := client.DoTimeout(httpReq, httpResp, 10*time.Second)
	if err != nil {
		preview := URLPreview{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		}
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(preview)
		return
	}

	if httpResp.StatusCode() != fasthttp.StatusOK {
		preview := URLPreview{
			Error: fmt.Sprintf("HTTP error: %d", httpResp.StatusCode()),
		}
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(preview)
		return
	}

	body := httpResp.Body()
	title, description := extractTitleAndDescription(string(body))

	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(preview)
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not Found")
		}
	}

	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

