	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract description from meta tag
			if n.Data == "meta" {
				var content, name, property string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					case "property":
						property = attr.Val
					}
				}
				if (name == "description" || property == "og:description") && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Continue traversing if we haven't found both values
		if title == "" || description == "" {
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				f(c)
			}
		}
	}

	f(doc)

	// Limit title and description length
	if len(title) > 200 {
		title = title[:200] + "..."
	}
	if len(description) > 300 {
		description = description[:300] + "..."
	}

	return title, description, nil
}

// isPrivateIP checks if the hostname resolves to a private/internal IP address
func isPrivateIP(hostname string) bool {
	// Remove port if present
	if idx := strings.LastIndex(hostname, ":"); idx != -1 {
		hostname = hostname[:idx]
	}

	// Check for localhost or loopback
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Check for private network prefixes
	privatePrefixes := []string{
		"10.", "172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.", "172.24.",
		"172.25.", "172.26.", "172.27.", "172.28.", "172.29.",
		"172.30.", "172.31.", "192.168.", "169.254.",
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(hostname, prefix) {
			return true
		}
	}

	return false
}

