		}{title, description, err}
	}()

	select {
	case result := <-resultChan:
		return result.title, result.description, result.err
	case <-time.After(htmlParseTimeout):
		return "", "", fmt.Errorf("HTML parsing timeout")
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

// validateHost checks if the host is valid and not blocked
func validateHost(host string) error {
	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Check for localhost variants
	if strings.HasPrefix(strings.ToLower(host), "localhost") {
		return fmt.Errorf("localhost access blocked")
	}

	// Resolve IP to check if it's in blocked ranges
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %v", err)
	}

	for _, ip := range ips {
		if isBlockedIP(ip.String()) {
			return fmt.Errorf("access to internal IP blocked")
		}
	}

	return nil
}

// isBlockedIP checks if an IP is in blocked ranges
func isBlockedIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	for _, cidr := range blockedIPRanges {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// sanitizeText cleans and truncates text
func sanitizeText(text string, maxLength int) string {
	// Remove excessive whitespace
	text = strings.TrimSpace(text)
	text = regexp.MustCompile(`\s+`).ReplaceAllString(text, " ")

	// Truncate if too long
	if len(text) > maxLength {
		text = text[:maxLength] + "..."
	}

	return text
}

