// FetchURLPreview handles POST requests with JSON containing a URL,
// fetches the HTML content, extracts title and meta description
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Only POST method is allowed")
		return
	}

	// Parse JSON request
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendErrorResponse(ctx, "Invalid JSON format", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if req.URL == "" {
		sendErrorResponse(ctx, "URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Basic URL validation
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		sendErrorResponse(ctx, "URL must start with http:// or https://", fasthttp.StatusBadRequest)
		return
	}

	// Create request and response objects
	reqObj := fasthttp.AcquireRequest()
	respObj := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqObj)
	defer fasthttp.ReleaseResponse(respObj)

	// Set up the request with timeout
	reqObj.SetRequestURI(req.URL)
	reqObj.Header.SetMethod(fasthttp.MethodGet)
	reqObj.SetConnectionClose()

	// Perform the request with redirect handling and timeout
	err := client.DoTimeout(reqObj, respObj, 15*time.Second)
	if err != nil {
		sendErrorResponse(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	statusCode := respObj.StatusCode()
	if statusCode != fasthttp.StatusOK {
		sendErrorResponse(ctx, fmt.Sprintf("HTTP request failed with status: %d", statusCode), fasthttp.StatusInternalServerError)
		return
	}

	// Limit response size for security
	body := respObj.Body()
	if len(body) > 10*1024*1024 { // 10MB limit
		sendErrorResponse(ctx, "Response too large", fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML to extract title and description
	title, description := extractMetadata(body)

	// Prepare and send response
	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		sendErrorResponse(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// extractMetadata parses HTML content and extracts title and meta description
func extractMetadata(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = cleanText(n.FirstChild.Data)
			}
			if n.Data == "meta" {
				var metaName, content string
				for _, attr := range n.Attr {
