						metaName = attr.Val
					}
					if attr.Key == "content" {
						content = cleanText(attr.Val)
					}
				}
				if metaName == "description" && content != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

// cleanText removes extra whitespace and newlines from text
func cleanText(text string) string {
	// Replace multiple whitespace characters with a single space
	text = strings.Join(strings.Fields(text), " ")
	// Trim spaces
	text = strings.TrimSpace(text)
	// Remove any non-printable characters
	return strings.Map(func(r rune) rune {
		if unicode.IsPrint(r) {
			return r
		}
		return -1
	}, text)
}

// sendErrorResponse sends a JSON error response
func sendErrorResponse(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	preview := URLPreview{
		Error: message,
	}
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	json.NewEncoder(ctx).Encode(preview)
}

func main() {
	// Register the handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-url-preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
